sql:
SELECT address
FROM properties
WHERE listing_date > '2023-01-01' AND status = 'active';

SELECT AVG(list_price) AS average_listing_price
FROM properties
WHERE community_id = 1 AND agent_id = 1;

external_knowledge:
- 'Enchanted keys' refers to MLS identifiers; 
- 'Harbingers of fortune' refers to the agents' names;
- 'Majestic houses' implies properties with at least four bedrooms and three bathrooms;
- 'Price tag' refers to the listing price;
- 'Average value' refers to the average sale price;
- 'Doors were unlocked' refers to transactions occurring within a specific date range;
- 'Seen the light' implies the property has at least one transaction.
